import anthropic
import base64

# Read a local image and base64-encode it
with open("chart.png", "rb") as f:
    image_data = base64.standard_b64encode(f.read()).decode("utf-8")

client = anthropic.Anthropic()  # reads ANTHROPIC_API_KEY from env

response = client.messages.create(
    model="claude-sonnet-4-5",
    max_tokens=1024,
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "image",
                    "source": {
                        "type": "base64",
                        "media_type": "image/png",
                        "data": image_data,
                    },
                },
                {"type": "text", "text": "Describe what you see in this chart."},
            ],
        }
    ],
)
print(response.content[0].text)

import openai
import base64

# Base64 path
with open("screenshot.png", "rb") as f:
    b64 = base64.b64encode(f.read()).decode()

client = openai.OpenAI()  # reads OPENAI_API_KEY from env

response = client.chat.completions.create(
    model="gpt-4o",
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "text",
                    "text": "What is shown in this screenshot?",
                },
                {
                    "type": "image_url",
                    "image_url": {
                        "url": f"data:image/png;base64,{b64}",
                        "detail": "high",  # or 'low' for cheaper, faster processing
                    },
                },
            ],
        }
    ],
)
print(response.choices[0].message.content)

import google.generativeai as genai
import base64

genai.configure(api_key="YOUR_GEMINI_API_KEY")

with open("diagram.jpg", "rb") as f:
    image_bytes = f.read()

model = genai.GenerativeModel("gemini-1.5-pro")

response = model.generate_content([
    {
        "inline_data": {
            "mime_type": "image/jpeg",
            "data": base64.b64encode(image_bytes).decode(),
        }
    },
    "Explain the diagram in simple terms.",
])
print(response.text)
